    // Check if the URL has a username and password
    const urlObject = new URL(url);
    if (urlObject.username && urlObject.password) {
        // Create a new URL object without the username and password
        const newUrl = new URL(urlObject.origin + urlObject.pathname + urlObject.search + urlObject.hash);
        return newUrl.href;
    } else {
        // If the URL doesn't have a username and password, return the original URL
        return url;
