public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    protected readonly DbContext _context;
    protected readonly DbSet<T> _dbSet;

    public BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = _context.Set<T>();
    }

    public virtual async Task<T> GetByIdAsync(int id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync()
    {
        return await _dbSet.ToListAsync();
    }

    public virtual async Task<T> GetByDynamicFieldAsync(string field, object value)
    {
        // Using Expression to dynamically build the expression
        var parameter = Expression.Parameter(typeof(T));
        var member = Expression.PropertyOrField(parameter, field);
        var constant = Expression.Constant(value);
        var body = Expression.Equal(member, constant);
        var lambda = Expression.Lambda<Func<T, bool>>(body, parameter);

        return await _dbSet.FirstOrDefaultAsync(lambda);
    }

    // Other methods...
}
